var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"세상에… 이게 누구인가?","JPN":"おやまあ……これはこれは！","ENG":"Good heavens... Look who it is!","TWN":"我的天……這是誰啊？"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오랜만에 뵙는군요, 촌장님.","JPN":"お久しぶりです、村長。","ENG":"It's been a while, Chief.","TWN":"許久不見，村長。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그동안 잘 지내셨습니까?","JPN":"お元気にしていらっしゃいましたか？","ENG":"Have you been well?","TWN":"這段時間過得好嗎？"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"말도 마라. 그동안 관리국에서 사람을 보내서 어찌나 고생이었는지.","JPN":"いや、今まで管理局から何度も人が来て大変だったぞ。","ENG":"Don't get me started. The Administration sent someone over, and it was a mess.","TWN":"別提了。這段時間管理局派來的人讓我吃了不少苦頭。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"교수님의 거처가 어디냐고 물어보는데, 무슨 일이 생긴 줄 알고 내가 다 조마조마했다.","JPN":"教授の居場所をしつこく聞いてくるもんだから、何かあったのかとヒヤヒヤしたんだが。","ENG":"They were asking about the Professor's whereabouts, and I was worried something might've happened.","TWN":"有人問教授的住處在哪裡，我還以為出了什麼事，緊張得不得了。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"너나 오빠도 요새 연락이 통 안되었으니…….","JPN":"お前たち兄妹も最近はまるで音沙汰がなかったしな……","ENG":"Neither you nor your brother had been in touch lately...","TWN":"你和哥哥最近也一直聯絡不上……"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 근래 들어 바빴던 지라 연락할 틈이 없었군요.","JPN":"すみません。近頃は忙しくて、連絡をする余裕もありませんでした。","ENG":"I apologize. Things have been hectic lately, and I haven't had a chance to reach out.","TWN":"抱歉，最近比較忙，沒時間聯絡你。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"버밍엄 교수님의 일은… 아마 관리국에서 협조를 요청할 일이 있었나 봅니다.","JPN":"バーミンガム教授の件は……たぶん、管理局から何か協力要請でもあったんでしょう。","ENG":"As for Professor Birmingham... I imagine the Administration needed his cooperation with something.","TWN":"伯明罕教授的事情……可能是管理局請求協助的事情吧。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"큰 일은 아닐 테니 촌장님께서 걱정하실 필요는 없을 것 같군요.","JPN":"大事ではないと思いますし、村長が心配されることはありません。","ENG":"It likely wasn't anything serious, so there's no need for concern.","TWN":"這不是什麼大事，村長你不必擔心。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"하긴, 걱정할 사람이 따로 있지. 늙은이가 괜한 오지랖을 부렸구만.","JPN":"ふむ……私が心配することでもなかったか。年寄りがお節介を焼いてしまったな。","ENG":"True. I suppose it's not my place to worry. Just an old man meddling where he shouldn't.","TWN":"也是，該擔心的人另有其人。老頭子真是多管閒事了。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"교수님이야 당연하고, 기사단장인 네 오빠에게 별 일이야 있겠어?","JPN":"教授もそうだが、騎士団長を務めるお前の兄さんに何かあるわけもなかろう。","ENG":"It's not like anything could happen to the professor or to your brother, the captain.","TWN":"教授當然沒問題，你哥哥作為騎士團長會有什麼事呢？"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……예. 그렇죠.","JPN":"……はい、もちろんです。","ENG":"...Yes, of course.","TWN":"……是的。沒錯。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"오랜만에 왔으니, 어떠냐. 마을 사람들을 모아 밥이라도 먹는 건?","JPN":"久しぶりに戻ったんだ。どうだ？　村の者を集めて、食事でも一緒にしないか？","ENG":"Now that you're back, how about it? Shall we gather the villagers and have a meal together?","TWN":"好久不見，怎麼樣？要不要召集村民們一起吃頓飯？"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 당장 급한 일이 있어 그것부터 처리해야 할 것 같군요.","JPN":"申し訳ありません。急ぎの用事がありまして、まずそちらを片付けねばならないのです。","ENG":"I'm sorry. There's something urgent I need to take care of first.","TWN":"對不起。我有急事需要馬上處理。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오늘은 버밍엄 교수님의 거처에 용무가 있어 찾아왔습니다.","JPN":"今日はバーミンガム教授の家に用があって参りました。","ENG":"I came to check the professor's residence today.","TWN":"今天我有事要去拜訪伯明罕教授的住處。"},"stage":{"bg":"PRIDE_COUNTRY","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"열렸네. 이제 들어가봐도 좋아.","JPN":"開いたぞ、入りなさい。","ENG":"It's open. You can go in.","TWN":"開了。現在可以進去看看了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"감사합니다, 촌장님.","JPN":"ありがとうございます、村長。","ENG":"Thank you, Chief.","TWN":"好的，村長。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"감사 인사는 됐네. 바쁜데 얼굴 비추러 와준 것만해도 고맙지.","JPN":"礼はいらん。忙しい中、顔を見せてくれただけでもありがたい。","ENG":"No need to thank me. I appreciate you even stopping by when you're so busy.","TWN":"道謝就不必了。你能在百忙之中抽空來見我，我已經很感激了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"교수님이 돌아오기 힘들 것 같다며 열쇠를 맡기셨을 땐 무슨 일인가 싶어 불안했는데…….","JPN":"教授がもう戻れそうにないからと鍵を預けていったときには、何事かと心配になったが……","ENG":"When the Professor handed me the key saying he might not return, I feared the worst...","TWN":"教授說他可能無法回來，把鑰匙交給我時，我感到不安，不知道發生了什麼事……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"자네가 이렇게 소식을 전해줬으니, 오늘은 마음 편히 잠들 수 있겠어.","JPN":"お前がこうして来てくれたわけだし、今夜はぐっすり眠れそうだ。","ENG":"But now that you've brought news, I can finally rest easy tonight.","TWN":"既然你帶來了這個消息，今天我可以安心入睡了。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"이런, 내가 바쁜 사람을 붙잡았구만.","JPN":"おっと、忙しい人を引き留めてしまったな。","ENG":"Oh dear, I've been holding up someone who's busy.","TWN":"哎呀，我耽誤了忙人的時間。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"늙은이는 이만 가볼 테니 편히 둘러보게.","JPN":"年寄りはこの辺で失礼するよ。ゆっくり見ていきなさい。","ENG":"I'll get going. Take your time looking around.","TWN":"我這把老骨頭就先走了，你們隨意看看吧。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"알렌 경의 방 답지 않게, 먼지가 자욱하군.","JPN":"アレン卿の部屋らしくもない、すっかり埃まみれだな。","ENG":"This doesn't feel like Sir Allen's room at all. So dusty...","TWN":"艾倫卿的房間不像平時那樣，滿是灰塵。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"청소. 자주 하라 말했으면서…….","JPN":"掃除はこまめにしろとあれだけ私に小言を言っておいて……","ENG":"He always said to keep it clean...","TWN":"打掃。明明說過要經常打掃的……"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"정신 차려. 추억이나 회상하려고 여기까지 온 게 아니야.","JPN":"いや、しっかりしろ。思い出に浸るためにここに来たわけじゃない。","ENG":"Focus. I didn't come here to wallow in nostalgia.","TWN":"振作點。我們不是來這裡追憶往事的。"},"stage":{"bg":"WOODHOUSE","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};